/* ── SEO Link Injection v1 ── */
/* Injects hidden product links on brand category pages for Google discovery */
(function() {
  'use strict';
  
  // Only run on category pages
  var path = window.location.pathname;
  var catMatch = path.match(/category-s\/(\d+)\.htm/i);
  if (!catMatch) return;
  
  var catId = catMatch[1];
  
  // Check if we have links for this category
  if (typeof window.__catLinks === 'undefined' || !window.__catLinks[catId]) return;
  
  var urls = window.__catLinks[catId];
  if (!urls || !urls.length) return;
  
  // Build link container - visually hidden but crawlable
  // Using clip-rect method which is SEO-safe (not display:none)
  var container = document.createElement('nav');
  container.id = 'seo-product-links';
  container.setAttribute('aria-label', 'All products in this category');
  container.style.cssText = 'position:absolute;width:1px;height:1px;padding:0;margin:-1px;overflow:hidden;clip:rect(0,0,0,0);white-space:nowrap;border:0;';
  
  // Build links
  var html = '<ul role="list">';
  urls.forEach(function(url) {
    html += '<li><a href="' + url + '">Product</a></li>';
  });
  html += '</ul>';
  
  container.innerHTML = html;
  
  // Inject at start of body
  function inject() {
    if (document.body && !document.getElementById('seo-product-links')) {
      document.body.insertBefore(container, document.body.firstChild);
    }
  }
  
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', inject);
  } else {
    inject();
  }
})();
